// src/controllers/AuthController.js
import AuthService from '../services/AuthService';

const AuthController = {
  async handleLogin(email, password, navigate, toast) {
    try {
      await AuthService.login(email, password);

      toast.success('Login realizado com sucesso!');
      navigate('/dashboard');
    } catch (error) {
      const msg = error.message || 'Erro ao fazer login';
      if (msg.includes('Invalid login credentials')) {
        toast.error('Senha incorreta. Verifique suas credenciais.');
      } else if (msg.includes('Email not confirmed')) {
        toast.error('Confirme seu e-mail antes de entrar.');
      } else {
        toast.error(msg);
      }
    }
  },

  async handleRegister(formData, navigate, toast) {
    const { email, password, confirmPassword, name } = formData;

    if (!name || name.trim().length < 2) {
      toast.error('Nome deve ter ao menos 2 caracteres.');
      return;
    }

    if (password !== confirmPassword) {
      toast.error('As senhas não coincidem.');
      return;
    }

    if (password.length < 6) {
      toast.error('A senha deve ter ao menos 6 caracteres.');
      return;
    }

    try {
      await AuthService.register(email, password, name.trim());
      toast.success('Conta criada! Faça login para continuar.');
      navigate('/login');
    } catch (error) {
      const msg = error.message || 'Erro ao criar conta';
      if (msg.includes('User already registered')) {
        toast.error('Este email já está cadastrado.');
      } else {
        toast.error(msg);
      }
    }
  },

  async handleLogout(navigate, toast) {
    try {
      await AuthService.logout();
      toast.success('Até logo!');
      navigate('/login');
    } catch (error) {
      toast.error('Erro ao sair.');
    }
  }
};

export default AuthController;
